/**
 * Filter registry entries by query (fuzzy match on ticker + name).
 * Returns max `limit` results.
 */
export function searchTickers(
    query: string,
    type: "s" | "c" | "all" = "all",
    limit: number = 8
): TickerEntry[] {
    if (!query || query.trim().length === 0) return [];
    const q = query.toLowerCase().trim();

    const filtered = TICKER_REGISTRY.filter((e) => {
        if (type !== "all" && e.y !== type) return false;
        return e.t.toLowerCase().includes(q) || e.n.toLowerCase().includes(q);
    });

    // Sort: exact ticker match first, then starts-with, then includes
    filtered.sort((a, b) => {
        const aExact = a.t.toLowerCase() === q ? 0 : 1;
        const bExact = b.t.toLowerCase() === q ? 0 : 1;
        if (aExact !== bExact) return aExact - bExact;

        const aStarts = a.t.toLowerCase().startsWith(q) ? 0 : 1;
        const bStarts = b.t.toLowerCase().startsWith(q) ? 0 : 1;
        if (aStarts !== bStarts) return aStarts - bStarts;

        const aNameStarts = a.n.toLowerCase().startsWith(q) ? 0 : 1;
        const bNameStarts = b.n.toLowerCase().startsWith(q) ? 0 : 1;
        return aNameStarts - bNameStarts;
    });

    return filtered.slice(0, limit);
}

/**
 * Live equity search against Yahoo (via /api/symbol-search), so ANY listed
 * stock — every small-cap — is findable, not just the curated registry.
 * Returns [] on error. Crypto stays registry-only (CoinGecko ids).
 */
export async function searchTickersLive(query: string, signal?: AbortSignal): Promise<TickerEntry[]> {
    const q = query.trim();
    if (q.length < 2) return [];
    try {
        const res = await fetch(`/api/symbol-search?q=${encodeURIComponent(q)}`, { signal });
        if (!res.ok) return [];
        const data = await res.json() as { results?: TickerEntry[] };
        return Array.isArray(data.results) ? data.results : [];
    } catch {
        return [];
    }
}

/** Merge registry + live results, registry first, deduped by symbol+type. */
export function mergeTickerResults(local: TickerEntry[], live: TickerEntry[], limit = 10): TickerEntry[] {
    const seen = new Set(local.map((e) => `${e.t.toLowerCase()}_${e.y}`));
    const merged = [...local];
    for (const e of live) {
        const key = `${e.t.toLowerCase()}_${e.y}`;
        if (!seen.has(key)) { seen.add(key); merged.push(e); }
    }
    return merged.slice(0, limit);
}
